{"type": "email", "id": "email_001", "subject": "AI Anomaly Detection Tool Integration", "from": "jordan.lee@mediconn.com", "from_name": "Jordan Lee", "to": ["michelle.morgan@mediconn.com", "david.johnson@mediconn.com", "sarah.green@mediconn.com", "peter.brown@mediconn.com"], "cc": ["emily.wilson@mediconn.com"], "date": "2026-04-01 10:15:00", "body": "Dear Team,

